Modified regret-based insertion evaluating both nearest neighbor distance ratio and temporal urgency, prioritizing high-regret orders first while maintaining feasibility through backup states and fallback to new assign.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	shipCount := len(oris)
	if shipCount != len(dess) {
		return dispatch
	}

	type candidate struct {
		assignIdx int
		costDelta float64
		state     Assign
	}

	for sIdx := 0; sIdx < shipCount; sIdx++ {
		bestCandidate := candidate{costDelta: 1e18}
		shipID := total_ship + sIdx
		ori := oris[sIdx]
		des := dess[sIdx]

		regretScore := 0.0
		if ori.TimeEnd > 0 && des.TimeStart > 0 {
			timeUrgency := float64(ori.TimeEnd - ori.TimeStart)
			if timeUrgency > 0 {
				regretScore += 1.0 / timeUrgency
			}
		}
		distRatio := cal_dis(ori, des)
		if distRatio > 0 {
			regretScore *= distRatio
		}

		maxTries := dispatch.AssignsLen
		if maxTries > MAXASSIGNS {
			maxTries = MAXASSIGNS
		}

		for aIdx := 0; aIdx < maxTries; aIdx++ {
			saved := dispatch.Assigns[aIdx]
			success := dispatch.Assigns[aIdx].AddShip(shipID, ori, des)
			if !success {
				continue
			}
			oldCost := dispatch.Assigns[aIdx].Cost
			dispatch.Assigns[aIdx].GenRoute()
			newCost := dispatch.Assigns[aIdx].Cost
			if newCost < 0 || oldCost < 0 {
				dispatch.Assigns[aIdx] = saved
				continue
			}
			delta := newCost - oldCost
			score := delta*(1.0+regretScore*0.5)
			if score < bestCandidate.costDelta {
				bestCandidate.assignIdx = aIdx
				bestCandidate.costDelta = score
				bestCandidate.state = dispatch.Assigns[aIdx]
			}
			dispatch.Assigns[aIdx] = saved
		}

		if bestCandidate.costDelta < 1e17 {
			targetIdx := bestCandidate.assignIdx
			dispatch.Assigns[targetIdx] = bestCandidate.state
		} else {
			targetIdx := dispatch.AssignsLen
			foundEmpty := false
			if targetIdx >= MAXASSIGNS {
				for i := 0; i < MAXASSIGNS; i++ {
					if dispatch.Assigns[i].StationsLen == 0 {
						targetIdx = i
						foundEmpty = true
						break
					}
				}
			}
			if targetIdx < MAXASSIGNS {
				var emptyAssign Assign
				if !foundEmpty && targetIdx >= dispatch.AssignsLen {
					dispatch.Assigns[targetIdx] = emptyAssign
				}
				saved := dispatch.Assigns[targetIdx]
				success := dispatch.Assigns[targetIdx].AddShip(shipID, ori, des)
				if success {
					dispatch.Assigns[targetIdx].GenRoute()
					if dispatch.Assigns[targetIdx].Cost >= 0 {
						if targetIdx >= dispatch.AssignsLen && !foundEmpty {
							dispatch.AssignsLen++
						}
					} else {
						dispatch.Assigns[targetIdx] = saved
					}
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

